// Build the data structure
for (const [planet, sign, interp] of interpretations) {
  if (!data[planet]) data[planet] = {};
  data[planet][sign] = { planet, sign, ...interp };
}

// For planets/signs without specific interpretations, generate a generic but useful one
for (const p of planets) {
  if (!data[p]) data[p] = {};
  for (const s of signs) {
    if (!data[p][s]) {
      const signData = {
        Aries: { element: 'fire', trait: 'bold and direct' },
        Taurus: { element: 'earth', trait: 'steady and practical' },
        Gemini: { element: 'air', trait: 'communicative and adaptable' },
        Cancer: { element: 'water', trait: 'emotional and nurturing' },
        Leo: { element: 'fire', trait: 'creative and expressive' },
        Virgo: { element: 'earth', trait: 'analytical and detail-oriented' },
        Libra: { element: 'air', trait: 'diplomatic and harmonious' },
        Scorpio: { element: 'water', trait: 'intense and transformative' },
        Sagittarius: { element: 'fire', trait: 'adventurous and philosophical' },
        Capricorn: { element: 'earth', trait: 'ambitious and disciplined' },
        Aquarius: { element: 'air', trait: 'innovative and independent' },
        Pisces: { element: 'water', trait: 'compassionate and intuitive' },
      }[s] || { element: 'fire', trait: 'unique' };

      data[p][s] = {
        planet: p,
        sign: s,
        coreMeaning: `${p} in ${s} combines the ${p.toLowerCase()} domain of energy with the ${signData.trait} qualities of ${s}. This placement expresses ${p.toLowerCase()} themes through a ${signData.element}-element lens, creating a personality style that is both dynamic and grounded in ${s} characteristics.`,
        strengths: [`Expresses ${p.toLowerCase()} energy in a ${signData.trait} way`, `Natural alignment between ${p.toLowerCase()} themes and ${s} qualities`, `Ability to channel ${p.toLowerCase()} energy productively`],
        challenges: [`May need to balance ${p.toLowerCase()} energy with ${s} tendencies`, `Potential conflict between ${p.toLowerCase()} themes and ${s} challenges`],
        inLove: `With ${p} in ${s}, your love style is influenced by both ${p.toLowerCase()} themes and ${s} qualities. You approach relationships with a ${signData.trait} energy that colors how you express and receive affection.`,
        atWork: `This placement suggests a work style that combines ${p.toLowerCase()} energy with ${s} qualities. You may excel in environments that allow both ${p.toLowerCase()} expression and ${s}-aligned approaches.`,
        growthArea: `Your growth lies in integrating ${p.toLowerCase()} themes with ${s} qualities, finding harmony between these two archetypes in your personality.`,
        journalPrompt: `How do I notice ${p.toLowerCase()} energy showing up in my life through the lens of ${s}?`
      };
    }
  }
}

// Aspect interpretations
export interface AspectInterpretation {
  name: string;
  angle: string;
  symbol: string;
  nature: 'harmonious' | 'challenging' | 'neutral';
  description: string;
  advice: string;
}

export const aspectInterpretations: AspectInterpretation[] = [
  { name: 'Conjunction', angle: '0 degrees', symbol: '\u260C', nature: 'neutral', description: 'A conjunction occurs when two planets are at approximately the same degree in the zodiac. This is the most powerful aspect in astrology, combining and intensifying the energies of both planets. The conjunction creates a fused energy where the two planetary functions operate as a unified force in your personality. The nature of this aspect depends entirely on the planets involved. Beneficial planetary combinations create enhanced talents, while challenging combinations create internal tension that demands resolution and growth. A conjunction always represents a significant theme in your personality that cannot be ignored.', advice: 'Identify which two energies are combined and find constructive ways to express them together. The conjunction demands integration rather than choosing between the two planetary functions. Journal about moments when both energies are active simultaneously in your life.' },
  { name: 'Sextile', angle: '60 degrees', symbol: '\u262C', nature: 'harmonious', description: 'A sextile occurs when two planets are approximately 60 degrees apart, representing an opportunity for productive cooperation between different areas of your life. This aspect suggests natural talent and ease between the two planetary energies, but unlike the trine, the sextile requires some effort to activate its full potential. Think of it as an open door that you still need to walk through. The sextile often connects signs of complementary elements, creating a dynamic tension that can be harnessed for growth and achievement.', advice: 'Look for opportunities to combine the two energies in creative projects or problem-solving. The sextile rewards initiative and effort, so take action when you feel this aspect\'s energy activated. This is a growth area where your natural talents can be developed with relatively small amounts of focused effort.' },
  { name: 'Square', angle: '90 degrees', symbol: '\u25A1', nature: 'challenging', description: 'A square occurs when two planets are approximately 90 degrees apart, creating dynamic tension between different areas of your life. This is one of the most important aspects for personal growth because it identifies areas where you must actively work to integrate conflicting needs and energies. The square creates friction, challenge, and often frustration, but this friction is the engine of personal development. People with significant squares in their chart are often the most driven, accomplished, and self-aware because they have been forced to confront and integrate internal conflicts throughout their lives.', advice: 'Rather than trying to eliminate the tension of the square, learn to work with it constructively. Identify the two competing needs and find creative ways to honor both. The square\'s energy is best channeled into physical activity, creative projects, or structured problem-solving. Avoiding the tension only makes it resurface with greater intensity.' },
  { name: 'Trine', angle: '120 degrees', symbol: '\u25B3', nature: 'harmonious', description: 'A trine occurs when two planets are approximately 120 degrees apart, typically connecting signs of the same element. This is the most harmonious aspect in astrology, creating a natural flow of energy between the two planetary functions. The trine represents areas of natural talent, ease, and good fortune in your personality. Things tend to come easily in the areas governed by a trine, which is both a blessing and a potential pitfall. Because the energy flows so naturally, people sometimes take their trine talents for granted and fail to develop them fully.', advice: 'Appreciate your natural talents but do not become complacent about them. The trine\'s gifts are most powerful when actively developed and shared with others. Challenge yourself to grow beyond what comes easily and use your trine talents as a foundation for exploring more challenging aspects of your personality.' },
  { name: 'Opposition', angle: '180 degrees', symbol: '\u260C', nature: 'challenging', description: 'An opposition occurs when two planets are approximately 180 degrees apart, creating a polarity between two opposing areas of your life. This aspect represents a fundamental tension between two needs or energies that both demand expression but pull in opposite directions. The opposition often manifests through relationships, where you project one side of the opposition onto others and attract people who embody the energy you find hardest to express yourself. Learning to integrate both poles of an opposition is one of the most transformative experiences in personal growth.', advice: 'Recognize that both ends of the opposition represent valid needs that must be honored, not a choice between right and wrong. The goal is not to eliminate the tension but to find a dynamic balance that allows both energies to express appropriately. Relationships are often the arena where oppositions are most activated, so pay attention to recurring relationship patterns for clues about your oppositions.' },
];

